async (params, browser) => {
  // Open product page
  await browser.open(`${params.product_url}`)

  // Wait for page to load
  await browser.waitForSelector('h1, [data-test=\'post-name\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to reviews/comments section
  await browser.scroll({ direction: 'down', amount: 3000 })

  await browser.wait(2000)

  // Scroll to load more reviews
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Extract reviews
  const reviews_data = await browser.evaluate(`const reviews = []; const reviewEls = document.querySelectorAll('[class*="comment"], [class*="review"], [data-test="comment"], [class*="Comment"]'); for (let i = 0; i < Math.min(reviewEls.length, 20); i++) { const el = reviewEls[i]; const authorEl = el.querySelector('[class*="user"] a, [class*="author"] a, [data-test="comment-user"]'); const contentEl = el.querySelector('[class*="body"], [class*="content"] p, [class*="text"]'); const dateEl = el.querySelector('time, [class*="date"], [class*="timestamp"]'); const upvotesEl = el.querySelector('[class*="vote"] span, [class*="upvote"] span'); const ratingEl = el.querySelector('[class*="rating"], [class*="stars"]'); const isMaker = !!el.querySelector('[class*="maker"], [class*="badge"]'); if (contentEl && contentEl.textContent.trim().length > 0) { reviews.push({ author: authorEl ? authorEl.textContent.trim() : 'Anonymous', content: contentEl ? contentEl.textContent.trim().substring(0, 500) : '', date: dateEl ? (dateEl.getAttribute('datetime') || dateEl.textContent.trim()) : '', upvotes: upvotesEl ? upvotesEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', is_maker: isMaker }); } } return { scraped_count: reviews.length, reviews: reviews, url: window.location.href }`)

  return reviews_data
}
